    emit(-0.0);                                   /* erfc(-0) = 1.0 */
    emit_u(0x7ff8000000000000ULL);                /* qNaN */
    emit_u(0x7ff0000000000001ULL);                /* sNaN */
    emit_u(0xfff8000000000000ULL);                /* -qNaN */
    emit_u(0x7ff0000000000000ULL);                /* +Inf -> erfc = 0 */
    emit_u(0xfff0000000000000ULL);                /* -Inf -> erfc = 2 */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);                /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);                /* min negative subnormal */
    emit_u(0x0008000000000000ULL);                /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);                /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);                /* max subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);                /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(DBL_MIN);                                /* 2^-1022, smallest normal */
    emit(-DBL_MIN);
    emit_u(0x0010000000000001ULL);                /* one ULP above DBL_MIN */
    emit_u(0x7fefffffffffffffULL);                /* DBL_MAX: erfc saturates to 0 */

    /* --- Section 4: Near 1.0 ULP neighbors (6) --- */
    emit_u(0x3fefffffffffffffULL);                /* one ULP below 1.0 */
    emit(1.0);                                    /* erfc(1) ~ 0.1573 */
    emit_u(0x3ff0000000000001ULL);                /* one ULP above 1.0 */
    emit(-1.0);                                   /* erfc(-1) ~ 1.8427 */
    emit_u(0xbfefffffffffffffULL);                /* one ULP below -1.0 (toward zero) */
    emit_u(0xbff0000000000001ULL);                /* one ULP above -1.0 (away from zero) */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3fe0000000000000ULL);                /* 0.5 */
    emit_u(0x3fdffffffffffffeULL);                /* one ULP below 0.5 */
    emit_u(0x3fe0000000000001ULL);                /* one ULP above 0.5 */
    emit_u(0x4000000000000000ULL);                /* 2.0 */
    emit_u(0x3fffffffffffffffULL);                /* one ULP below 2.0 */
    emit_u(0x4000000000000001ULL);                /* one ULP above 2.0 */

    /* --- Section 6: erfc-specific mathematical constants (14) --- */
    emit(0.1);                                    /* near-zero Taylor path */
    emit(-0.1);
    emit(0.01);                                   /* deep near-zero */
    emit(-0.01);
    emit(1.0e-10);                                /* erfc ~ 1.0 - tiny correction */
    emit(-1.0e-10);
    emit(0.5);                                    /* erfc(0.5) ~ 0.4795 */
    emit(-0.5);                                   /* erfc(-0.5) ~ 1.5205 */
    emit(1.5);                                    /* erfc(1.5) ~ 0.0339 */
    emit(-1.5);
    emit(2.5);                                    /* erfc(2.5) ~ 4.678e-4 */
    emit(-2.5);
    emit_u(0x3fe62e42fefa39efULL);                /* ln2 ~ 0.693: mid polynomial regime */
    emit_u(0xbfe62e42fefa39efULL);                /* -ln2 */

    /* --- Section 7: Algorithm switchover boundaries (10) --- */
    /* erfc implementations typically switch approximations at |x| = 0.5, 1, 2, 4, 6 */
    emit_u(0x3fe0000000000000ULL);                /* 0.5 boundary */
    emit_u(0xbfe0000000000000ULL);                /* -0.5 boundary */
    emit_u(0x4000000000000000ULL);                /* 2.0 switchover */
    emit_u(0xc000000000000000ULL);                /* -2.0 switchover */
    emit_u(0x4010000000000000ULL);                /* 4.0 switchover */
    emit_u(0xc010000000000000ULL);                /* -4.0 switchover */
    emit_u(0x4018000000000000ULL);                /* 6.0 switchover */
    emit_u(0xc018000000000000ULL);                /* -6.0 switchover */
    emit_u(0x4008000000000000ULL);                /* 3.0 */
    emit_u(0xc008000000000000ULL);                /* -3.0 */

    /* --- Section 8: ULP neighbors of key erfc transitions (12) --- */
    /* Around x = 1.0 (erfc changes from near-1 to near-0 regime) */
    emit_u(0x3feffffffffffffeULL);                /* 2 ULP below 1.0 */
    emit_u(0x3ff0000000000002ULL);                /* 2 ULP above 1.0 */
    /* Around x = 2.0 (erfc transitions to asymptotic expansion) */
    emit_u(0x3ffffffffffffeULL);                  /* 2 ULP below 2.0 */
    emit_u(0x4000000000000002ULL);                /* 2 ULP above 2.0 */
    /* Around x = 4.0 */
    emit_u(0x400fffffffffffffULL);                /* one ULP below 4.0 */
    emit_u(0x4010000000000001ULL);                /* one ULP above 4.0 */
    /* Around x = -1.0 */
    emit_u(0xbfeffffffffffffeULL);                /* 2 ULP below -1.0 (toward zero) */
    emit_u(0xbff0000000000002ULL);                /* 2 ULP above -1.0 (away from zero) */
    /* Around x = 0.5 */
    emit_u(0x3fdfffffffffffffULL);                /* one ULP below 0.5 */
    emit_u(0x3fe0000000000002ULL);                /* 2 ULP above 0.5 */
    /* Around x = -0.5 */
    emit_u(0xbfdffffffffffffeULL);                /* 2 ULP below -0.5 (toward zero) */
    emit_u(0xbfe0000000000001ULL);                /* one ULP above -0.5 (away from zero) */

