    emit_u(0x403b800000000000ULL);                /* 27.5: near erfc underflow to 0 */
    emit_u(0x4040000000000000ULL);                /* 32.0: erfc = 0 */
    /* erfc saturates to 2 for large negative x */
    emit(-5.0);
    emit(-10.0);
    emit(-20.0);
    emit(-27.0);
    emit_u(0xc040000000000000ULL);                /* -32.0: erfc = 2 */

    /* --- Section 10: Hard rounding and polynomial stress (20) --- */
    emit(0.25);                                   /* erfc(0.25) ~ 0.7237 */
    emit(-0.25);
    emit(0.75);                                   /* erfc(0.75) ~ 0.2888 */
    emit(-0.75);
    emit(1.25);                                   /* erfc(1.25) ~ 0.0897 */
    emit(-1.25);
    emit(1.75);                                   /* erfc(1.75) ~ 0.0145 */
    emit(-1.75);
    emit(2.25);
    emit(-2.25);
    emit(3.5);
    emit(-3.5);
    emit(4.5);
    emit(-4.5);
    emit_u(0x3ff921fb54442d18ULL);                /* pi/2 ~ 1.5708: mid polynomial */
    emit_u(0xbff921fb54442d18ULL);                /* -pi/2 */
    emit_u(0x400921fb54442d18ULL);                /* pi ~ 3.1416: mid asymptotic */
    emit_u(0xc00921fb54442d18ULL);                /* -pi */
    emit_u(0x4005bf0a8b145769ULL);                /* e ~ 2.7183 */
    emit_u(0xc005bf0a8b145769ULL);                /* -e */
